"""注册、登录和个人资料 HTTP 边界。"""

import re
import secrets
from typing import Annotated

from fastapi import APIRouter, Depends, Header, HTTPException, status
from pydantic import BaseModel, ConfigDict, field_validator

from sample_service.auth_security import (
    ACCESS_TOKEN_TTL_SECONDS,
    hash_password,
    issue_access_token,
    verify_access_token,
    verify_password,
)
from sample_service.user_repository import (
    EmailAlreadyRegisteredError,
    UserRecord,
    UserRepository,
)

PASSWORD_MIN_LENGTH = 8
PASSWORD_MAX_LENGTH = 128
DISPLAY_NAME_MAX_LENGTH = 50

_EMAIL_PATTERN = re.compile(
    r"^[A-Za-z0-9.!#$%&'*+/=?^_`{|}~-]+@"
    r"[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?"
    r"(?:\.[A-Za-z0-9](?:[A-Za-z0-9-]{0,61}[A-Za-z0-9])?)+$"
)


class RegisterRequest(BaseModel):
    """用户注册请求。"""

    model_config = ConfigDict(extra="forbid")

    email: str
    password: str
    display_name: str

    @field_validator("email")
    @classmethod
    def normalize_email(cls, value: str) -> str:
        """统一去除空白并转为小写，且拒绝不完整的邮件地址。"""

        normalized = value.strip().lower()
        if len(normalized) > 254 or _EMAIL_PATTERN.fullmatch(normalized) is None:
            raise ValueError("email 格式错误")
        return normalized

    @field_validator("password")
    @classmethod
    def validate_password(cls, value: str) -> str:
        """密码边界按字符数判断，不隐式修改用户输入。"""

        if not PASSWORD_MIN_LENGTH <= len(value) <= PASSWORD_MAX_LENGTH:
            raise ValueError("password 长度必须为 8 到 128 个字符")
        return value

    @field_validator("display_name")
    @classmethod
    def normalize_display_name(cls, value: str) -> str:
        """显示名称持久化前去除首尾空白。"""

        normalized = value.strip()
        if not 1 <= len(normalized) <= DISPLAY_NAME_MAX_LENGTH:
            raise ValueError("display_name 长度必须为 1 到 50 个字符")
        return normalized


class LoginRequest(BaseModel):
    """用户登录请求。"""

    model_config = ConfigDict(extra="forbid")

    email: str
    password: str

    @field_validator("email")
    @classmethod
    def normalize_email(cls, value: str) -> str:
        """登录与注册使用相同的邮箱规范化规则。"""

        return RegisterRequest.normalize_email(value)

    @field_validator("password")
    @classmethod
    def limit_password_length(cls, value: str) -> str:
        """在进入 scrypt 前限制攻击者可控输入体量。"""

        if len(value) > PASSWORD_MAX_LENGTH:
            raise ValueError("password 最长为 128 个字符")
        return value


class ProfileUpdateRequest(BaseModel):
    """当前用户资料更新请求。"""

    model_config = ConfigDict(extra="forbid")

    display_name: str

    @field_validator("display_name")
    @classmethod
    def normalize_display_name(cls, value: str) -> str:
        """复用注册时的显示名称约束。"""

        return RegisterRequest.normalize_display_name(value)


class PublicUser(BaseModel):
    """可以安全返回给 API 调用方的用户字段。"""

    model_config = ConfigDict(extra="forbid")

    id: str
    email: str
    display_name: str
    created_at: str


class AccessTokenResponse(BaseModel):
    """登录成功返回的 Bearer token 契约。"""

    model_config = ConfigDict(extra="forbid")

    access_token: str
    token_type: str = "bearer"
    expires_in: int = ACCESS_TOKEN_TTL_SECONDS


def build_auth_router(repository: UserRepository, token_secret: bytes) -> APIRouter:
    """装配认证与资料路由，所有依赖由应用工厂显式注入。"""

    router = APIRouter()
    authorization_header = Annotated[
        str | None,
        Header(alias="Authorization"),
    ]

    def current_user(authorization: authorization_header = None) -> UserRecord:
        """从 Bearer token 解析当前用户，所有失败使用同一外部错误。"""

        if authorization is None or not authorization.startswith("Bearer "):
            raise _invalid_access_token()
        token = authorization.removeprefix("Bearer ").strip()
        if not token or " " in token:
            raise _invalid_access_token()
        user_id = verify_access_token(token, token_secret)
        if user_id is None:
            raise _invalid_access_token()
        record = repository.find_by_id(user_id)
        if record is None:
            raise _invalid_access_token()
        return record

    @router.post(
        "/auth/register",
        response_model=PublicUser,
        status_code=status.HTTP_201_CREATED,
        tags=["auth"],
    )
    def register(payload: RegisterRequest) -> PublicUser:
        """创建持久化用户，唯一性冲突返回稳定错误码。"""

        try:
            record = repository.create_user(
                email=payload.email,
                password_hash=hash_password(payload.password),
                display_name=payload.display_name,
            )
        except EmailAlreadyRegisteredError as exc:
            raise HTTPException(
                status_code=status.HTTP_409_CONFLICT,
                detail={
                    "code": "email_already_registered",
                    "message": "该邮箱已注册。",
                },
            ) from exc
        return _public_user(record)

    @router.post(
        "/auth/login",
        response_model=AccessTokenResponse,
        tags=["auth"],
    )
    def login(payload: LoginRequest) -> AccessTokenResponse:
        """校验凭据并签发 30 分钟 token，不泄露账号是否存在。"""

        record = repository.find_by_email(payload.email)
        password_hash = (
            record.password_hash
            if record is not None
            else _DUMMY_PASSWORD_HASH
        )
        if not verify_password(payload.password, password_hash) or record is None:
            raise _invalid_credentials()
        return AccessTokenResponse(
            access_token=issue_access_token(record.id, token_secret),
        )

    @router.get(
        "/profile",
        response_model=PublicUser,
        tags=["profile"],
    )
    def get_profile(
        record: Annotated[UserRecord, Depends(current_user)],
    ) -> PublicUser:
        """只返回 token 所属用户的公开字段。"""

        return _public_user(record)

    @router.patch(
        "/profile",
        response_model=PublicUser,
        tags=["profile"],
    )
    def update_profile(
        payload: ProfileUpdateRequest,
        record: Annotated[UserRecord, Depends(current_user)],
    ) -> PublicUser:
        """更新当前用户显示名称，不允许跨用户选择目标。"""

        updated = repository.update_display_name(record.id, payload.display_name)
        return _public_user(updated)

    return router


def _public_user(record: UserRecord) -> PublicUser:
    """显式投影公开字段，避免持久化字段意外进入响应。"""

    return PublicUser(
        id=str(record.id),
        email=record.email,
        display_name=record.display_name,
        created_at=record.created_at.isoformat(),
    )


def _invalid_credentials() -> HTTPException:
    """返回不区分账号状态的登录错误。"""

    return HTTPException(
        status_code=status.HTTP_401_UNAUTHORIZED,
        detail={
            "code": "invalid_credentials",
            "message": "邮箱或密码错误。",
        },
        headers={"WWW-Authenticate": "Bearer"},
    )


def _invalid_access_token() -> HTTPException:
    """返回统一的 Bearer token 错误。"""

    return HTTPException(
        status_code=status.HTTP_401_UNAUTHORIZED,
        detail={
            "code": "invalid_access_token",
            "message": "access token 无效或已过期。",
        },
        headers={"WWW-Authenticate": "Bearer"},
    )


_DUMMY_PASSWORD_HASH = hash_password(secrets.token_urlsafe(32))
